/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Skeleton Loading Components
   Dark theme shimmer animation with design system colors.
   Variants: SkeletonTable, SkeletonChart, SkeletonCard, SkeletonStat
   ═══════════════════════════════════════════════════════════════════════════ */

const COLORS = {
  base: '#161B22',
  highlight: '#1C2128',
  border: '#30363D',
};

const shimmerCSS = `
@keyframes aura-shimmer {
  0% { background-position: -400px 0; }
  100% { background-position: 400px 0; }
}
`;

let injected = false;
function injectShimmer() {
  if (injected || typeof document === 'undefined') return;
  injected = true;
  const style = document.createElement('style');
  style.textContent = shimmerCSS;
  document.head.appendChild(style);
}

function ShimmerBar({ width = '100%', height = 14, delay = 0, borderRadius = 4, style = {} }) {
  injectShimmer();
  return (
    <div
      style={{
        width,
        height,
        borderRadius,
        background: `linear-gradient(90deg, ${COLORS.base} 0%, ${COLORS.highlight} 40%, #21262D 50%, ${COLORS.highlight} 60%, ${COLORS.base} 100%)`,
        backgroundSize: '400px 100%',
        backgroundRepeat: 'no-repeat',
        animation: 'aura-shimmer 1.6s linear infinite',
        animationDelay: `${delay}s`,
        ...style,
      }}
    />
  );
}

/* ════════════════════════════════════════════════════════════════
   SkeletonTable — shimmer table with configurable rows/columns
   ════════════════════════════════════════════════════════════════ */
export function SkeletonTable({ rows = 6, columns = 5 }) {
  const cellWidths = ['60%', '80%', '50%', '70%', '45%', '55%', '65%', '40%', '75%', '35%'];
  return (
    <div
      aria-busy="true"
      aria-label="Loading table data"
      style={{
        width: '100%',
        backgroundColor: COLORS.base,
        border: `1px solid ${COLORS.border}`,
        borderRadius: 12,
        overflow: 'hidden',
      }}
    >
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr>
            {Array.from({ length: columns }).map((_, i) => (
              <th
                key={i}
                style={{
                  padding: '12px 14px',
                  borderBottom: `1px solid ${COLORS.border}`,
                  backgroundColor: COLORS.base,
                }}
              >
                <ShimmerBar width="70%" height={10} delay={i * 0.06} />
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {Array.from({ length: rows }).map((_, r) => (
            <tr key={r}>
              {Array.from({ length: columns }).map((_, c) => (
                <td
                  key={c}
                  style={{
                    padding: '11px 14px',
                    borderBottom: r < rows - 1 ? `1px solid ${COLORS.border}` : 'none',
                  }}
                >
                  <ShimmerBar
                    width={cellWidths[(r + c) % cellWidths.length]}
                    height={14}
                    delay={(r * columns + c) * 0.03}
                  />
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   SkeletonChart — rectangle placeholder with axis lines
   ════════════════════════════════════════════════════════════════ */
export function SkeletonChart({ height = 260 }) {
  return (
    <div
      aria-busy="true"
      aria-label="Loading chart"
      style={{
        width: '100%',
        height,
        borderRadius: 12,
        backgroundColor: COLORS.base,
        border: `1px solid ${COLORS.border}`,
        position: 'relative',
        overflow: 'hidden',
      }}
    >
      {/* Y-axis labels */}
      <div style={{ position: 'absolute', left: 14, top: 22, display: 'flex', flexDirection: 'column', gap: 36 }}>
        {Array.from({ length: 4 }).map((_, i) => (
          <ShimmerBar key={i} width={34} height={10} delay={i * 0.1} />
        ))}
      </div>

      {/* Grid lines */}
      {Array.from({ length: 4 }).map((_, i) => (
        <div
          key={`g-${i}`}
          style={{
            position: 'absolute',
            left: 60,
            right: 16,
            top: 26 + i * 46,
            height: 1,
            background: `${COLORS.border}60`,
          }}
        />
      ))}

      {/* Chart area shimmer */}
      <ShimmerBar
        width="auto"
        height="auto"
        delay={0.15}
        borderRadius={6}
        style={{
          position: 'absolute',
          left: 60,
          right: 16,
          top: 22,
          bottom: 38,
          opacity: 0.5,
        }}
      />

      {/* X-axis labels */}
      <div style={{
        position: 'absolute',
        bottom: 12,
        left: 60,
        right: 16,
        display: 'flex',
        justifyContent: 'space-between',
      }}>
        {Array.from({ length: 6 }).map((_, i) => (
          <ShimmerBar key={i} width={34} height={8} delay={0.1 * i} />
        ))}
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   SkeletonCard — card placeholder with header area + lines
   ════════════════════════════════════════════════════════════════ */
export function SkeletonCard({ width = '100%', height = 180, lines = 3 }) {
  return (
    <div
      aria-busy="true"
      aria-label="Loading card"
      style={{
        width,
        minHeight: height,
        borderRadius: 12,
        backgroundColor: COLORS.base,
        border: `1px solid ${COLORS.border}`,
        padding: 18,
        display: 'flex',
        flexDirection: 'column',
        gap: 14,
        boxSizing: 'border-box',
      }}
    >
      {/* Header area */}
      <ShimmerBar width="100%" height={Math.floor(height * 0.3)} borderRadius={8} delay={0} />
      {/* Text lines */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
        {Array.from({ length: lines }).map((_, i) => (
          <ShimmerBar
            key={i}
            width={i === lines - 1 ? '60%' : `${85 - i * 8}%`}
            height={12}
            delay={0.1 + i * 0.08}
          />
        ))}
      </div>
      {/* Footer metric row */}
      <div style={{ display: 'flex', gap: 12, marginTop: 'auto' }}>
        <ShimmerBar width="25%" height={10} delay={0.3} />
        <ShimmerBar width="20%" height={10} delay={0.35} />
        <ShimmerBar width="22%" height={10} delay={0.4} />
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   SkeletonStat — single stat/metric tile (label + value)
   ════════════════════════════════════════════════════════════════ */
export function SkeletonStat({ delay = 0 }) {
  return (
    <div
      aria-busy="true"
      aria-label="Loading stat"
      style={{
        flex: '1 1 0',
        minWidth: 130,
        backgroundColor: COLORS.base,
        border: `1px solid ${COLORS.border}`,
        borderRadius: 12,
        padding: '16px 20px',
        display: 'flex',
        flexDirection: 'column',
        gap: 10,
      }}
    >
      <ShimmerBar width="55%" height={10} delay={delay} />
      <ShimmerBar width="40%" height={24} delay={delay + 0.1} />
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   SkeletonStatRow — row of stat tiles
   ════════════════════════════════════════════════════════════════ */
export function SkeletonStatRow({ count = 4 }) {
  return (
    <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap', width: '100%' }}>
      {Array.from({ length: count }).map((_, i) => (
        <SkeletonStat key={i} delay={i * 0.1} />
      ))}
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   SkeletonPage — full page skeleton: stat row + chart + table
   Replaces "Loading..." text on any data-heavy page.
   ════════════════════════════════════════════════════════════════ */
export function SkeletonPage({ statCount = 4, tableRows = 6, tableCols = 5, chartHeight = 200 }) {
  return (
    <div
      style={{
        padding: '20px 24px',
        display: 'flex',
        flexDirection: 'column',
        gap: 20,
        minHeight: '100%',
      }}
    >
      <ShimmerBar width={220} height={26} delay={0} borderRadius={6} />
      <SkeletonStatRow count={statCount} />
      <SkeletonChart height={chartHeight} />
      <SkeletonTable rows={tableRows} columns={tableCols} />
    </div>
  );
}

export default {
  SkeletonTable,
  SkeletonChart,
  SkeletonCard,
  SkeletonStat,
  SkeletonStatRow,
  SkeletonPage,
};
